import React from 'react';
import { FormData, Category } from '../types';
import { categories } from '../constants';
import CategorySection from './CategorySection';

interface SummaryPageProps {
  formData: FormData;
  onBack: () => void;
  onConfirm: () => void;
  sending: boolean;
}

const SummaryPage: React.FC<SummaryPageProps> = ({
  formData,
  onBack,
  onConfirm,
  sending
}) => {
  return (
    <div style={{ background: 'var(--color-bg)', minHeight: '100vh', padding: 'var(--space-3)' }}>
      <h1 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-3)' }}>Order Summary</h1>
      <div style={{ background: 'var(--color-bg-alt)', borderRadius: 'var(--radius)', padding: 'var(--space-3)', marginBottom: '2rem' }}>
        <h2 style={{ color: 'var(--color-primary)' }}>Store Information</h2>
        <div style={{ marginBottom: '1rem' }}><strong>Store Number:</strong> {formData.storeNumber}</div>
        <div style={{ marginBottom: '1rem' }}><strong>Store Manager:</strong> {formData.storeManager}</div>
        <div style={{ marginBottom: '1rem' }}><strong>Date:</strong> {formData.date}</div>
      </div>

      {categories.map((category: Category) => (
        <CategorySection
          key={category.name}
          category={category}
          quantities={formData.quantities}
          readOnly={true}
        />
      ))}

      <div style={{ display: 'flex', gap: '1rem', marginTop: '2rem' }}>
        <button
          type="button"
          onClick={onBack}
          style={{
            background: 'var(--color-primary)',
            color: 'white',
            padding: '12px 24px',
            border: 'none',
            borderRadius: 'var(--radius)',
            fontSize: '16px',
            cursor: 'pointer',
            flex: 1
          }}
        >
          Back
        </button>
        <button
          type="button"
          onClick={onConfirm}
          style={{
            background: 'var(--color-primary)',
            color: 'white',
            padding: '12px 24px',
            border: 'none',
            borderRadius: 'var(--radius)',
            fontSize: '16px',
            cursor: 'pointer',
            flex: 1
          }}
          disabled={sending}
        >
          {sending ? 'Sending...' : 'Confirm'}
        </button>
      </div>
    </div>
  );
};

export default SummaryPage;
